#include <sstream>
#include <string>

using namespace std;

string convertToBase36(long long num) {
    if (num == 0) return "0";
    string res;
    while (num > 0) {
        int rem = num % 36;
        char c;
        if (rem < 10) {
            c = '0' + rem;
        } else {
            c = 'A' + (rem - 10);
        }
        res.insert(res.begin(), c);
        num /= 36;
    }
    return res;
}

string solve(long long n) {
    long long n2 = n * n;
    long long n3 = n2 * n;

    ostringstream oss_hex;
    oss_hex << hex << uppercase << n2;
    string hex_str = oss_hex.str();

    string base36_str = convertToBase36(n3);

    return hex_str + base36_str;
}
